async function main() {
  console.log('\n🧪 SEED — Turma de Teste Piloto\n');
  const senhaHash = await bcrypt.hash('Teste@123', 10);

  // ── 0. Criar unidade de teste ───────────────────────────────────────────
  console.log('── Unidade de teste ──');
  const unitTeste = await prisma.unit.upsert({
    where: { id: UNIT_ID_TESTE },
    create: {
      id: UNIT_ID_TESTE,
      mantenedoraId: MANTENEDORA_ID,
      name: 'CEPI PILOTO — Ambiente de Testes',
      address: 'Ambiente de testes — não é uma unidade real',
      isActive: true,
      createdBy: 'seed-teste',
    },
    update: {},
  });
  console.log(`  ✅ Unidade: ${unitTeste.name}`);

  // ── 1. Professor teste ──────────────────────────────────────────────────
  console.log('── Professor de teste ──');
  const profTeste = await prisma.user.upsert({
    where: { email: 'professor.teste@conexa.test' },
    create: {
      mantenedoraId: MANTENEDORA_ID,
      unitId: UNIT_ID_TESTE,
      email: 'professor.teste@conexa.test',
      password: senhaHash,
      firstName: 'PROFESSORA',
      lastName: 'PILOTO',
      status: 'ATIVO',
      createdBy: 'seed-teste',
      updatedBy: 'seed-teste',
    },
    update: {},
  });
  const existingRole = await prisma.userRole.findUnique({
    where: { userId_roleId: { userId: profTeste.id, roleId: ROLE_PROFESSOR_ID } },
  });
  if (!existingRole) {
    await prisma.userRole.create({
      data: { userId: profTeste.id, roleId: ROLE_PROFESSOR_ID, scopeLevel: 'PROFESSOR', isActive: true },
    });
  }
  console.log('  ✅ professor.teste@conexa.test / Teste@123');

  // ── 2. Turma teste ──────────────────────────────────────────────────────
  console.log('\n── Turma de teste ──');
  const classroom = await prisma.classroom.upsert({
    where: { unitId_code: { unitId: UNIT_ID_TESTE, code: CLASSROOM_CODE } },
    create: {
      unitId: UNIT_ID_TESTE, name: 'Maternal II — PILOTO (Turma de Teste)',
      code: CLASSROOM_CODE, ageGroupMin: 48, ageGroupMax: 71,
      capacity: 12, isActive: true, createdBy: 'seed-teste',
    },
    update: {},
  });
  await prisma.classroomTeacher.upsert({
    where: { classroomId_teacherId: { classroomId: classroom.id, teacherId: profTeste.id } },
    create: { classroomId: classroom.id, teacherId: profTeste.id, role: 'MAIN', isActive: true },
    update: {},
  });
  console.log(`  ✅ Turma: ${classroom.name} (${classroom.id})`);

  // ── 3. Alunos e matrículas ──────────────────────────────────────────────
  console.log('\n── Alunos ──');
  const childMap = new Map<string, string>(); // codigoAluno → id
  for (const a of ALUNOS) {
    const child = await prisma.child.upsert({
      where: { cpf: a.cpf },
      create: {
        mantenedoraId: MANTENEDORA_ID, unitId: UNIT_ID_TESTE,
        firstName: a.firstName, lastName: a.lastName,
        cpf: a.cpf, codigoAluno: a.codigoAluno, inscricao: a.inscricao,
        dateOfBirth: new Date(a.dateOfBirth), gender: a.gender as any,
        raca: a.raca, bloodType: a.bloodType,
        nomeMae: a.nomeMae, nomePai: a.nomePai,
        emergencyContactPhone: a.emergencyContactPhone,
        laudado: a.laudado ?? false,
        tipoLaudo: a.tipoLaudo ?? null,
        cid: a.cid ?? null,
        descricaoLaudo: a.descricaoLaudo ?? null,
        medicamentos: a.medicamentos ?? null,
        isActive: true, createdBy: 'seed-teste', updatedBy: 'seed-teste',
      },
      update: { tipoLaudo: a.tipoLaudo, cid: a.cid, descricaoLaudo: a.descricaoLaudo, medicamentos: a.medicamentos },
    });
    childMap.set(a.codigoAluno, child.id);

    await prisma.enrollment.upsert({
      where: { childId_classroomId: { childId: child.id, classroomId: classroom.id } },
      create: { childId: child.id, classroomId: classroom.id, enrollmentDate: new Date('2026-02-03'), status: 'ATIVA', createdBy: 'seed-teste' },
      update: {},
    });

    // Restrições alimentares
    const restricoes = RESTRICOES[a.codigoAluno] ?? [];
    for (const r of restricoes) {
      const existing = await prisma.dietaryRestriction.findFirst({
        where: { childId: child.id, name: r.name }
      });
      if (!existing) {
        await prisma.dietaryRestriction.create({
          data: { childId: child.id, type: r.type, name: r.name, severity: r.severity, forbiddenFoods: r.forbiddenFoods ?? null, allowedFoods: r.allowedFoods ?? null, isActive: true, createdBy: 'seed-teste' }
        });
      }
    }
    console.log(`  ✅ ${a.firstName} ${a.lastName}${a.laudado ? ` (${a.tipoLaudo})` : ''}`);
  }

  // ── 4. Planos de aula ───────────────────────────────────────────────────
  console.log('\n── Planos de aula ──');
  const planningMap = new Map<string, string>(); // date → planningId
  for (const p of PLANEJAMENTOS) {
    const existing = await prisma.planning.findFirst({
      where: { classroomId: classroom.id, title: p.title }
    });
    if (existing) {
      planningMap.set(p.date, existing.id);
      continue;
    }
    const startDate = new Date(`${p.date}T08:00:00.000Z`);
    const endDate   = new Date(`${p.date}T17:00:00.000Z`);
    // Calcular próxima sexta-feira
    const d = new Date(startDate);
    while (d.getDay() !== 5) d.setDate(d.getDate() + 1);
    const planning = await prisma.planning.create({
      data: {
        mantenedoraId: MANTENEDORA_ID, unitId: UNIT_ID_TESTE,
        classroomId: classroom.id, createdById: profTeste.id,
        title: p.title, startDate, endDate: new Date(`${d.toISOString().slice(0,10)}T17:00:00.000Z`),
        status: 'EM_EXECUCAO',
        activities: `Objetivo: ${p.objetivo}\n\nDesenvolvimento:\n1. Acolhimento e roda de conversa (15min)\n2. Atividade principal: ${p.title} (30min)\n3. Registro e fechamento (15min)`,
        recursos: 'Materiais pedagógicos disponíveis na sala',
        createdBy: 'seed-teste',
      }
    });
    planningMap.set(p.date, planning.id);
    console.log(`  ✅ ${p.date}: ${p.title}`);
  }

  // ── 5. Eventos do diário ────────────────────────────────────────────────
  console.log('\n── Eventos do diário ──');
  let evtCriados = 0;

  // Agrupar por dia
  const eventosPorDia = new Map<string, any[]>();
  for (const e of DIARIO_EVENTOS) {
    if (!eventosPorDia.has(e.date)) eventosPorDia.set(e.date, []);
    eventosPorDia.get(e.date)!.push(e);
  }

  for (const [day, eventos] of eventosPorDia) {
    // Encontrar planningId para este dia
    let planningId: string | undefined;
    for (const [pDate, pId] of planningMap) {
      if (day >= pDate) planningId = pId;
    }

    for (const e of eventos) {
      const childId = childMap.get(e.childCode);
      if (!childId) continue;

      // Verificar se já existe
      const existing = await prisma.diaryEvent.findFirst({
        where: { childId, classroomId: classroom.id, type: e.type as any, eventDate: new Date(`${e.date}T12:00:00.000Z`) }
      });
      if (existing) continue;

      await prisma.diaryEvent.create({
        data: {
          mantenedoraId: MANTENEDORA_ID, unitId: UNIT_ID_TESTE,
          classroomId: classroom.id, childId,
          type: e.type as any,
          title: e.title,
          description: e.description,
          developmentNotes: e.developmentNotes ?? null,
          behaviorNotes: e.behaviorNotes ?? null,
          eventDate: new Date(`${e.date}T12:00:00.000Z`),
          status: 'PUBLICADO',
          ...(planningId ? { planningId } : {}),
          tags: [],
          mediaUrls: [],
          aiContext: { semana_tema: e.title },
          createdBy: profTeste.id,
        }
      });
      evtCriados++;
    }
    if (evtCriados % 50 === 0 && evtCriados > 0) console.log(`  ... ${evtCriados} eventos criados`);
  }
  console.log(`  ✅ ${evtCriados} eventos do diário criados`);

  console.log('\n🎉 Turma de teste criada com sucesso!');
  console.log('\n📋 RESUMO:');
  console.log('  Login: professor.teste@conexa.test');
  console.log('  Senha: Teste@123');
  console.log('  Turma: Maternal II — PILOTO (Turma de Teste)');
  console.log('  Alunos: 10 (com TEA, TDAH, TOD, Down, perfis variados)');
  console.log(`  Planos de aula: ${planningMap.size}`);
  console.log(`  Eventos diário: ${evtCriados}`);
  console.log('  Período: Fev–Abr 2026\n');
}

main().catch(console.error).finally(() => prisma.$disconnect());
